+impl VfxHarnessInput {
+    fn label(self) -> &'static str {
+        match self {
+            Self::Key { label, .. }
+            | Self::MouseMove { label, .. }
+            | Self::MouseDown { label, .. } => label,
+        }
+    }
+
+    fn to_event(self) -> Event {
+        match self {
+            Self::Key { code, kind, .. } => Event::Key(KeyEvent::new(code).with_kind(kind)),
